import { Injectable } from '@angular/core';
import { HttpClient,HttpParams } from '@angular/common/http';
import { Observable } from 'rxjs';
import { Magic } from '../models/magic';
import { MagicDetail } from '../models/magic-detail';

@Injectable({
  providedIn: 'root'
})
export class MagicService {
  private apiUrl = 'https://ced.discloud.app/api/magias/';

  constructor(private http: HttpClient) { }

  getMagics(): Observable<{ count: number, results: Magic[] }> {
    return this.http.get<{ count: number, results: Magic[] }>(this.apiUrl);
  }

  getMagicDetail(index: string): Observable<MagicDetail> {
    return this.http.get<MagicDetail>(`${this.apiUrl}${index}`);
  }

  getFilteredMagics(levels?: number[], school?: string, className?: string): Observable<{ count: number, results: Magic[] }> {
    let params = new HttpParams();

    // Adiciona múltiplos valores para 'level'
    if (levels && levels.length > 0) {
      levels.forEach(level => {
        params = params.append('level', level.toString()); // Adiciona cada nível separadamente
      });
    }console.log(params.toString());

    // Adiciona escola e classe se existirem
    if (school) {
      params = params.set('schoolName', school);
    }
    if (className) {
      params = params.set('className', className);
    }
    params = params.set('className', className);

    // Faz a requisição com os parâmetros criados
    return this.http.get<{ count: number, results: Magic[] }>(`${this.apiUrl}search`, { params });
  }


}
